// Shared types for Docker stack operations. Keeping them in one place makes it
// easier to unit test helpers without importing the entire service class.
import type { DockerStack, DockerStackDeployment } from '../../db';

export type SourceType = 'template' | 'paste' | 'registry' | 'pm2_migration' | 'github' | 'upload' | 'migration';
export type StackStatus = 'pending' | 'deploying' | 'running' | 'partial' | 'stopped' | 'error';
export type DeploymentStatus = 'pending' | 'pulling' | 'building' | 'starting' | 'success' | 'failed';
export type TriggerType = 'manual' | 'redeploy' | 'webhook' | 'pm2_migration' | 'git_push' | 'rollback' | 'external';
export type PullPolicy = 'always' | 'missing' | 'never';
/**
 * How the Docker image was built/deployed:
 * - 'vps': Built directly on the VPS (default for template/paste)
 * - 'github-actions': Built via GitHub Actions CI/CD, pushed to GHCR
 * - 'local-build': Built locally on user's machine, streamed to VPS via docker save/load
 */
export type BuildLocation = 'vps' | 'github-actions' | 'local-build';

export interface DeployStackInput {
  serverId: string;
  projectName: string;
  sourceType: SourceType;
  templateId?: string;
  composeContent: string;
  dockerfileContent?: string;
  /**
   * GitHub-only: if set, Server Compass will deploy using this Dockerfile path
   * (relative to the repo root) instead of the repository's default Dockerfile.
   *
   * Intended for "on-the-fly" overrides that are committed to the repo, e.g.:
   * - Dockerfile.servercompass
   */
  dockerfileOverridePath?: string;
  envVars?: Record<string, string>;
  stackPath?: string;
  registryCredentialId?: string;
  buildOnDeploy?: boolean;
  pullPolicy?: PullPolicy;
  notifyOnCompletion?: boolean;
  // Git-related fields for GitHub deployment
  gitAccountId?: string;
  gitRepository?: string; // format: "owner/repo"
  gitBranch?: string;
  gitPullOnRedeploy?: boolean;
  appPort?: number; // Port mapping for the container (host port)
  /**
   * How the image is built. Affects redeploy behavior:
   * - 'vps': Can pull images from registry
   * - 'github-actions': Can pull from GHCR
   * - 'local-build': Must skip pull (image only exists on VPS)
   */
  buildLocation?: BuildLocation;
  /**
   * Upload source: path to uploaded code on the VPS (e.g. /tmp/servercompass-upload-...).
   * Set when sourceType === 'upload'. The deploy logic will move this to {workingDir}/repo.
   */
  uploadFolderPath?: string;
}

export interface StackDeploymentResult {
  success: boolean;
  stackId?: string;
  deploymentId?: string;
  projectName?: string;
  services?: string[];
  containers?: ContainerInfo[];
  notificationScheduled?: boolean;
  error?: string;
  hostPort?: number; // Custom host port for environment deployments
}

export interface ContainerInfo {
  id: string;
  name: string;
  service: string;
  state: string;
  status: string;
  image: string;
  ports: Array<{ host?: number; container: number; protocol: 'tcp' | 'udp' }>;
  health?: string;
  cpuPercent?: string;
  memUsage?: string;
  memPercent?: string;
  // Docker inspect fields
  workingDir?: string;
  composeProjectWorkingDir?: string;
  mounts?: Array<{
    source: string;
    destination: string;
    type: string;
    mode?: string;
  }>;
}

export interface StackStatusInfo {
  stack: DockerStack;
  containers: ContainerInfo[];
  isHealthy: boolean;
}

export interface RedeployOptions {
  pullImages?: boolean;
  force?: boolean;
  pullLatestCode?: boolean;  // Force pull latest code from GitHub
  updateEnvOnly?: boolean;   // Just restart containers (no rebuild/pull)
  // Zero-downtime deployment options
  zeroDowntime?: boolean;    // Use zero-downtime deployment strategy
  gracePeriod?: number;      // Post-switch verification period (default: 30000ms)
  readinessTimeout?: number; // Pre-switch readiness timeout (default: 60000ms)
  // Build location change (for switching build type on redeploy)
  buildLocation?: 'vps' | 'github-actions' | 'local-build';
}

export interface LogEntry {
  message: string;
  type: 'info' | 'error' | 'success' | 'warning';
  timestamp: number;
  stackId?: string;
  deploymentId?: string;
}

export type { DockerStackDeployment };
